'use client';

import { usePathname } from 'next/navigation';
import Header from './Header';
import BottomNav from './BottomNav';

const HIDE_SHELL = ['/auth', '/onboarding'];

export default function ClientLayout({ children }: { children: React.ReactNode }) {
    const pathname = usePathname();
    const hideShell = HIDE_SHELL.some(p => pathname.startsWith(p));

    if (hideShell) {
        return <>{children}</>;
    }

    // Determine if content should overflow: hidden (swipe page)
    const isSwipe = pathname.startsWith('/swipe');

    return (
        <div className="app">
            <Header />
            <div className="content" style={{ overflow: isSwipe ? 'hidden' : 'auto' }}>
                {children}
            </div>
            <BottomNav />
        </div>
    );
}
